import { useState, useEffect } from 'react';
import { useLang } from '../context/LangContext';
import { subscribeToMemories, addMemory, deleteMemory } from '../firebase/firebaseConfig';
import './Memories.css';

export default function Memories() {
  const { t } = useLang();
  const [memories, setMemories] = useState([]);
  const [loading, setLoading]   = useState(true);
  const [title, setTitle]       = useState('');
  const [body, setBody]         = useState('');
  const [showForm, setShowForm] = useState(false);
  const [submitting, setSubmitting] = useState(false);
  const [toast, setToast]       = useState('');

  // Real-time Firestore subscription
  useEffect(() => {
    const unsub = subscribeToMemories((data) => {
      setMemories(data);
      setLoading(false);
    });
    return () => unsub();
  }, []);

  const showToast = msg => { setToast(msg); setTimeout(() => setToast(''), 2500); };

  const handleAdd = async () => {
    if (!title.trim() || !body.trim()) { showToast(t.fillBothFields); return; }
    setSubmitting(true);
    try {
      await addMemory({ title: title.trim(), body: body.trim() });
      setTitle(''); setBody(''); setShowForm(false);
      showToast(t.memorySaved);
    } catch {
      showToast('Error saving. Check Firebase config.');
    } finally {
      setSubmitting(false);
    }
  };

  const handleDelete = async (id) => {
    try {
      await deleteMemory(id);
      showToast(t.memoryRemoved);
    } catch {
      showToast('Error deleting memory.');
    }
  };

  return (
    <div>
      <h2 className="section-title">
        {t.ourMemoriesEm
          ? <>{t.ourMemories} <em>{t.ourMemoriesEm}</em></>
          : <em>{t.ourMemories}</em>}
      </h2>
      <p className="section-subtitle">{t.writtenFromHeart}</p>

      {showForm ? (
        <div className="memory-form card">
          <div className="form-field">
            <label className="form-label">{t.titleLabel}</label>
            <input
              className="form-input"
              type="text"
              placeholder={t.memTitlePlaceholder}
              maxLength={80}
              value={title}
              onChange={e => setTitle(e.target.value)}
            />
          </div>
          <div className="form-field">
            <label className="form-label">{t.messageLabel}</label>
            <textarea
              className="form-input"
              rows={5}
              placeholder={t.memBodyPlaceholder}
              value={body}
              onChange={e => setBody(e.target.value)}
            />
          </div>
          <div className="form-actions">
            <button className="btn-primary" onClick={handleAdd} disabled={submitting}>
              {submitting ? '...' : t.saveMemory}
            </button>
            <button className="btn-ghost" onClick={() => { setShowForm(false); setTitle(''); setBody(''); }}>
              {t.cancel}
            </button>
          </div>
        </div>
      ) : (
        <button className="btn-outline-gold" onClick={() => setShowForm(true)}>{t.addMemory}</button>
      )}

      {loading ? (
        <div className="memories-empty"><div className="empty-icon">✍️</div><p>Loading...</p></div>
      ) : memories.length === 0 && !showForm ? (
        <div className="memories-empty">
          <div className="empty-icon">✍️</div>
          <p>{t.noMemories.split('\n').map((l, i) => <span key={i}>{l}<br /></span>)}</p>
        </div>
      ) : (
        <div className="memories-list">
          {memories.map(mem => (
            <div key={mem.id} className="memory-card card">
              <div className="mem-top">
                <div className="mem-title">{mem.title}</div>
                <button className="mem-delete" onClick={() => handleDelete(mem.id)}>✕</button>
              </div>
              <div className="mem-body">{mem.body}</div>
              <div className="mem-date">{mem.date}</div>
            </div>
          ))}
        </div>
      )}

      {toast && <div className="mem-toast">{toast}</div>}
    </div>
  );
}
